/** 
 * The types of onboarding panels in the onboarding page
 */
enum class OnboardingPanel {
    
    /** 
     * The themes onboarding panel where users pick themes
     */
    THEMES,
    /** 
     * The onboarding panel where users can choose their total cookie protection
     * settings
     */
    TCP,
    /** 
     * The onboarding panel where users can tap to view our privacy notice.
     */
    PRIVACY_NOTICE,
    /** 
     * The onboarding panel where users choose their toolbar placement (bottom
     * or top)
     */
    TOOLBAR_PLACEMENT,
    /** 
     * The onboarding panel where users can sign in to sync
     */
    SYNC;

    companion object {
        private val enumMap: Map<String, OnboardingPanel> by lazy {
            mapOf(
                "themes" to OnboardingPanel.THEMES,
                "tcp" to OnboardingPanel.TCP,
                "privacy-notice" to OnboardingPanel.PRIVACY_NOTICE,
                "toolbar-placement" to OnboardingPanel.TOOLBAR_PLACEMENT,
                "sync" to OnboardingPanel.SYNC)
        }

        fun enumValue(string: String): OnboardingPanel? = enumMap[string]
    }
}



