    /** 
     * A local notification in the background, like a push notification.
     */
    NOTIFICATION,
    /** 
     * A banner in the homescreen.
     */
    HOMESCREEN;

    companion object {
        private val enumMap: Map<String, MessageSurfaceId> by lazy {
            mapOf(
                "notification" to MessageSurfaceId.NOTIFICATION,
                "homescreen" to MessageSurfaceId.HOMESCREEN)
        }

        fun enumValue(string: String): MessageSurfaceId? = enumMap[string]
    }
}



/** 
 * An enum to influence what should be displayed when a control message is
 * selected.
 */
enum class ControlMessageBehavior {
    
    /** 
     * The next eligible message should be shown.
     */
    SHOW_NEXT_MESSAGE,
    /** 
     * The surface should show no message.
     */
    SHOW_NONE;

    companion object {
        private val enumMap: Map<String, ControlMessageBehavior> by lazy {
            mapOf(
                "show-next-message" to ControlMessageBehavior.SHOW_NEXT_MESSAGE,
                "show-none" to ControlMessageBehavior.SHOW_NONE)
        }

        fun enumValue(string: String): ControlMessageBehavior? = enumMap[string]
    }
}



