/** 
 * The identifiers for the sections of the MR 2022.
 */
enum class CookieBannersSection {
    
    /** 
     * An integer either 0 or 1 indicating if cookie banner setting should be
     * enabled or disabled, 0 for setting the value to disabled, 1  for enabling
     * the setting with the value reject_all.
     */
    FEATURE_SETTING_VALUE,
    /** 
     * An integer indicating the number of hours that needs to happen before
     * the re-engagement dialog shows again since the last seen, for example if
     * set to 4 that means if the users has seen the dialog, it will see it 4
     * hours later.
     */
    DIALOG_RE_ENGAGE_TIME,
    /** 
     * An integer from 0 to 2, indicating which text variant should be used on
     * the re-engagement dialog. 0 to indicate the variant control should be
     * used, 1 indicates the variant 1 should be used, 2 indicates the variant
     * 2 should be used, each variant can be found in the mockups for cookie
     * banner handling.
     */
    DIALOG_TEXT_VARIANT,
    /** 
     * An integer either 0 or 1 indicating if the UI for cookie banner handling
     * should be visible, 0 to hide the UI and 1 to show the UI. The actual UI
     * is composed by cookie banner section in the settings page, the toolbar
     * section and the re-engagement dialog.
     */
    FEATURE_UI;

    companion object {
        private val enumMap: Map<String, CookieBannersSection> by lazy {
            mapOf(
                "feature-setting-value" to CookieBannersSection.FEATURE_SETTING_VALUE,
                "dialog-re-engage-time" to CookieBannersSection.DIALOG_RE_ENGAGE_TIME,
                "dialog-text-variant" to CookieBannersSection.DIALOG_TEXT_VARIANT,
                "feature-ui" to CookieBannersSection.FEATURE_UI)
        }

        fun enumValue(string: String): CookieBannersSection? = enumMap[string]
    }
}



