/** 
 * Attributes controlling the global configuration of notification messages.
 */
public class NotificationConfig
    private constructor(
      private val _variables: Variables,
      private val _defaults: Defaults) {
   
   private data class Defaults(
      val refreshInterval: Int
   )

   constructor(_variables: Variables = NullVariables.instance, 
      refreshInterval: Int = 240
   ) : this(
      _variables = _variables,
      _defaults = Defaults(refreshInterval = refreshInterval )
   )

   
   /** 
     * How often, in minutes, the notification message worker will wake up and
     * check for new messages.
     * 
     */
   val refreshInterval: Int by lazy {
      _variables.getInt("refresh-interval") ?: _defaults.refreshInterval
   }



    internal fun _mergeWith(defaults: NotificationConfig?): NotificationConfig =
        defaults?.let { NotificationConfig(_variables = this._variables, _defaults = it._defaults) } ?: this

    companion object {
        internal fun create(variables: Variables): NotificationConfig? =
            NotificationConfig(_variables = variables)

        internal fun mergeWith(overrides: NotificationConfig, defaults: NotificationConfig): NotificationConfig =
            overrides._mergeWith(defaults)
    }
}

/** 
 * An object to describe a message. It uses human readable strings to describe
 * the triggers, action and style of the message as well as the text of the
 * message and call to action.
 * 
 */
public class MessageData
    private constructor(
      private val _variables: Variables,
      private val _defaults: Defaults) {
   
   private data class Defaults(
      val action: StringHolder,
      val buttonLabel: StringHolder?,
      val isControl: Boolean,
      val style: String,
      val surface: MessageSurfaceId,
      val text: StringHolder,
      val title: StringHolder?,
      val trigger: List<String>
   )

   constructor(_variables: Variables = NullVariables.instance, 
      action: StringHolder = Res.string(R.string.empty_string),
      buttonLabel: StringHolder? = null,
      isControl: Boolean = false,
      style: String = "DEFAULT",
      surface: MessageSurfaceId = MessageSurfaceId.HOMESCREEN,
      text: StringHolder = Res.string(R.string.empty_string),
      title: StringHolder? = null,
      trigger: List<String> = listOf()
   ) : this(
      _variables = _variables,
      _defaults = Defaults(action = action, buttonLabel = buttonLabel, isControl = isControl, style = style, surface = surface, text = text, title = title, trigger = trigger )
   )

   
   /** 
     * A URL of a page or a deeplink. This may have substitution variables in.
     * 
     */
   val action: String by lazy {
      _variables.getText("action") ?: _defaults.action.toString(_variables.context)
   }

   /** 
     * The text on the button. If no text is present, the whole message is
     * clickable.
     * 
     */
   val buttonLabel: String? by lazy {
      _variables.getText("button-label") ?: _defaults.buttonLabel?.let { it.toString(_variables.context) }
   }

   /** 
     * Indicates if this message is the control message, if true shouldn't be
     * displayed
     */
   val isControl: Boolean by lazy {
      _variables.getBool("is-control") ?: _defaults.isControl
   }

   /** 
     * The style as described in a `StyleData` from the styles table.
     * 
     */
   val style: String by lazy {
      _variables.getString("style") ?: _defaults.style
   }

   /** 
     * The surface identifier for this message.
     */
   val surface: MessageSurfaceId by lazy {
      _variables.getString("surface")?.let(MessageSurfaceId::enumValue) ?: _defaults.surface
   }

   /** 
     * The message text displayed to the user
     */
   val text: String by lazy {
      _variables.getText("text") ?: _defaults.text.toString(_variables.context)
   }

   /** 
     * The title text displayed to the user
     */
   val title: String? by lazy {
      _variables.getText("title") ?: _defaults.title?.let { it.toString(_variables.context) }
   }

   /** 
     * A list of strings corresponding to targeting expressions. The message
     * will be shown if all expressions `true`.
     * 
     */
   val trigger: List<String> by lazy {
      _variables.getStringList("trigger") ?: _defaults.trigger
   }



    internal fun _mergeWith(defaults: MessageData?): MessageData =
        defaults?.let { MessageData(_variables = this._variables, _defaults = it._defaults) } ?: this

    companion object {
        internal fun create(variables: Variables): MessageData? =
            MessageData(_variables = variables)

        internal fun mergeWith(overrides: MessageData, defaults: MessageData): MessageData =
            overrides._mergeWith(defaults)
    }
}

/** 
 * A group of properties (predominantly visual) to describe the style of the
 * message.
 * 
 */
public class StyleData
    private constructor(
      private val _variables: Variables,
      private val _defaults: Defaults) {
   
   private data class Defaults(
      val maxDisplayCount: Int,
      val priority: Int
   )

   constructor(_variables: Variables = NullVariables.instance, 
      maxDisplayCount: Int = 5,
      priority: Int = 50
   ) : this(
      _variables = _variables,
      _defaults = Defaults(maxDisplayCount = maxDisplayCount, priority = priority )
   )

   
   /** 
     * How many sessions will this message be shown to the user before it is
     * expired.
     * 
     */
   val maxDisplayCount: Int by lazy {
      _variables.getInt("max-display-count") ?: _defaults.maxDisplayCount
   }

   /** 
     * The importance of this message. 0 is not very important, 100 is very
     * important.
     * 
     */
   val priority: Int by lazy {
      _variables.getInt("priority") ?: _defaults.priority
   }



    internal fun _mergeWith(defaults: StyleData?): StyleData =
        defaults?.let { StyleData(_variables = this._variables, _defaults = it._defaults) } ?: this

    companion object {
        internal fun create(variables: Variables): StyleData? =
            StyleData(_variables = variables)

        internal fun mergeWith(overrides: StyleData, defaults: StyleData): StyleData =
            overrides._mergeWith(defaults)
    }
}

